from sympy import integer_log, primefactors
def A394544(n):
    if n == 1: return 1
    x = 10**integer_log(n>>1,10)[0]
    y = 10*x
    return max(primefactors((c:=n-x)*x+int(str(c)[-2::-1] or '0') if n<x+y else (c:=n-y)*y+int(str(c)[::-1] or '0')),default=1) # _Chai Wah Wu_, Mar 30 2026

